    if (n < 4) return 0;

    const left_inc = new Array(n).fill(1);
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            left_inc[i] = left_inc[i - 1] + 1;
        }
    }

    const left_dec = new Array(n).fill(1);
    for (let i = 1; i < n; i++) {
        if (nums[i] < nums[i - 1]) {
            left_dec[i] = left_dec[i - 1] + 1;
        }
    }

    const right_inc = new Array(n).fill(1);
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            right_inc[i] = right_inc[i + 1] + 1;
        }
    }

    const right_dec = new Array(n).fill(1);
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] > nums[i + 1]) {
            right_dec[i] = right_dec[i + 1] + 1;
        }
    }

    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + nums[i];
    }

    let max_sum = -Infinity;

    for (let p = 0; p < n; p++) {
        if (left_inc[p] >= 2 && right_dec[p] >= 2) {
            const q = p + right_dec[p] - 1;
            if (right_inc[q] >= 2) {
                const r = q + right_inc[q] - 1;
                const l = p - left_inc[p] + 1;
                if (l < p && q < r) {
                    const current_sum = prefix[r + 1] - prefix[l];
                    if (current_sum > max_sum) {
                        max_sum = current_sum;
                    }
                }
            }
        }
    }

    return max_sum;
}
